                self.term = candidate_term
                self.voted_for = None
                self.state = "follower"
            elif candidate_term == self.term:
                if self.voted_for is None or self.node_id == event["candidate_id"]:
                    self.voted_for = event["candidate_id"]
        elif event["type"] == "heartbeat":
            if event["term"] > self.term:
                self.term = event["term"]
                self.voted_for = None
                self.state = "follower"
